const rawText =
  $input.first().json?.content?.parts?.[0]?.text ||
  $input.first().json?.text ||
  $input.first().json?.message?.content ||
  $input.first().json?.content ||
  "";

const coverLetterMarkdown = rawText
  .replace(/^```(json|markdown|text)?/im, "")
  .replace(/```$/m, "")
  .trim();

if (!coverLetterMarkdown) {
  throw new Error("Cover letter generation returned empty text.");
}

return [{
  json: {
    coverLetterMarkdown,
  },
}];

let rawOutput =
  $input.first().json?.content?.parts?.[0]?.text ||
  $input.first().json?.text ||
  $input.first().json?.message?.content ||
  "";

rawOutput = rawOutput
  .replace(/^```(json|markdown|text)?/im, "")
  .replace(/```$/m, "")
  .trim();

let refinedCvMarkdown = "";

const jsonMatch = rawOutput.match(/(\[[\s\S]*\])|(\{[\s\S]*\})/);
let parsedStructuredOutput = false;

if (jsonMatch) {
  try {
    let parsed = JSON.parse(jsonMatch[0]);

    if (Array.isArray(parsed)) {
      parsed = parsed[0];
    }

    const getValue = (value, keyName) => {
      if (!value || typeof value !== "object") {
        return null;
      }

      const key = Object.keys(value).find(
        (candidate) => candidate.toLowerCase() === keyName.toLowerCase()
      );

      return key ? value[key] : null;
    };

    const summary = getValue(parsed, "summary");
    const skills = getValue(parsed, "skills");
    const experience = getValue(parsed, "experience");

    if (summary || experience) {
      let builtMarkdown = `### Summary\n${summary || ""}\n\n### Skills\n`;

      if (skills && typeof skills === "object") {
        for (const [key, value] of Object.entries(skills)) {
          const cleanKey = key.includes("_")
            ? key
                .split("_")
                .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
                .join(" ")
                .replace(" And ", " & ")
            : key;

          builtMarkdown += `**${cleanKey}:** ${String(value)}\n`;
        }
      }

      builtMarkdown += `\n### Experience\n\n`;

      if (Array.isArray(experience)) {
        for (const job of experience) {
          const title = getValue(job, "title") || getValue(job, "role") || "";
          const company = getValue(job, "company") || "";
          const dates = getValue(job, "dates") || "";

          let header = title;

          if (company && !title.includes(company)) {
            header += ` | ${company}`;
          }

          builtMarkdown += `**${header}** | *${dates}*\n`;

          const bullets =
            getValue(job, "bullets") || getValue(job, "experience") || [];

          if (Array.isArray(bullets)) {
            for (const bullet of bullets) {
              builtMarkdown += `* ${String(bullet).replace(/\n/g, " ").trim()}\n`;
            }
          }

          builtMarkdown += `\n`;
        }
      }

      refinedCvMarkdown = builtMarkdown.trim();
      parsedStructuredOutput = true;
    }
  } catch {
    // fall back to plain markdown parsing below
  }
}

if (!parsedStructuredOutput) {
  refinedCvMarkdown = rawOutput
    .split(/(###\s*(Education|Languages)|EDUCATION\n)/i)[0]
    .trim();
}

const baseCv = $('cv-generation-start').first().json.body.baseCv;

function extractSection(text, sectionName) {
  const regex = new RegExp(`###\\s*${sectionName}\\s*\\n([\\s\\S]*?)(?=###|$)`, "i");
  const match = text.match(regex);
  return match ? match[1].trim() : "";
}

function extractHeader(text) {
  const lines = text.trim().split("\n");
  const nameLine = lines.find((line) => line.startsWith("#")) || lines[0] || "Candidate";
  const contactLine = lines.find((line) => line.includes("@") || line.includes("+")) || "";

  return {
    name: nameLine.replace(/^#+\s*/, "").trim(),
    contacts: contactLine.trim(),
  };
}

const education = extractSection(baseCv, "Education");
const languages = extractSection(baseCv, "Languages");
const { name, contacts } = extractHeader(baseCv);

const sections = [
  `# ${name}`,
  contacts ? `**${contacts}**` : "",
  "",
  "---",
  "",
  refinedCvMarkdown,
  education ? `### Education\n${education}` : "",
  languages ? `### Languages\n${languages}` : "",
].filter(Boolean);

return [{
  json: {
    cvMarkdown: sections.join("\n\n").trim(),
  },
}];

const rawText =
  $input.first().json?.content?.parts?.[0]?.text ||
  $input.first().json?.text ||
  $input.first().json?.message?.content ||
  $input.first().json?.content ||
  JSON.stringify($input.first().json);

if (!rawText) {
  throw new Error("Personal note generation returned empty text.");
}

const cleanText = rawText
  .replace(/^```(json|text|markdown)?/im, "")
  .replace(/```$/m, "")
  .trim();

let personalNote = "";

try {
  const parsedData = JSON.parse(cleanText);

  function extractString(data) {
    if (typeof data === "string") return data;
    if (Array.isArray(data)) return extractString(data[0]);
    if (typeof data === "object" && data !== null) {
      if (data.message) return extractString(data.message);
      if (data.note) return extractString(data.note);
      if (data.text) return extractString(data.text);
      return extractString(Object.values(data)[0]);
    }
    return String(data || "");
  }

  personalNote = extractString(parsedData);
} catch {
  personalNote = cleanText;
}

personalNote = personalNote.trim();

if (!personalNote) {
  throw new Error("Personal note generation returned empty text.");
}

return [{
  json: {
    personalNote,
  },
}];
